/* ─── Dynamic seed: replaces hardcoded IDs/actions from live /api/seed ─── */

function buildGuidedSpaceQuery() {
  const mode       = document.getElementById('space-guided-mode').value;
  const index      = document.getElementById('space-guided-index').value || 'inventory_v31';
  const locationId = Number(state.cbs.spaceGuidedLocation?.value) || 0;
  const productId  = Number(state.cbs.spaceGuidedProduct?.value)  || 0;
  document.getElementById('space-host-alias').value = 'astro-search-es';
  if (mode === 'doc') {
    document.getElementById('space-method').value = 'GET';
    if (state.cbs.spacePath) state.cbs.spacePath.value = `${index}/_doc/${locationId}-${productId}`;
    setSpaceBody('{}');
    return;
  }
  document.getElementById('space-method').value = 'POST';
  if (state.cbs.spacePath) state.cbs.spacePath.value = `${index}/_search`;
  if (mode === 'search-product') {
    setSpaceBody(JSON.stringify({ size: 10, query: { term: { product_id: productId } } }, null, 2));
  } else if (mode === 'search-location-product') {
    setSpaceBody(JSON.stringify({ size: 10, query: { bool: { must: [{ term: { product_id: productId } }, { term: { location_id: locationId } }] } } }, null, 2));
  } else {
    setSpaceBody(JSON.stringify({ size: 10, query: { match_all: {} } }, null, 2));
  }
}

async function runSpaceQuery() {
  const host      = document.getElementById('space-host-alias').value;
  const method    = document.getElementById('space-method').value;
  const queryPath = state.cbs.spacePath?.value || document.getElementById('cb-space-path')?.querySelector('.combobox-input')?.value || '_cat/indices?format=json';
  const bodyText  = getSpaceBody();
  let parsedBody  = {};
  try { parsedBody = bodyText.trim() ? JSON.parse(bodyText) : {}; }
  catch (e) { document.getElementById('space-query-output').textContent = `invalid JSON body: ${e}`; return; }
  const res     = await api('/api/space/query', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ host, method, path: queryPath, body: parsedBody }),
  });
  const payload = res.body || res;
  state.spaceLastResult = payload;
  document.getElementById('space-query-output').textContent = typeof res === 'string' ? res : JSON.stringify(payload, null, 2);
  renderSpaceQuerySummary(payload);
  syncJsonTree('space-query-output');
}

async function runSpaceDoc(locationId, productId) {
  const res     = await api(`/api/space/doc?locationId=${encodeURIComponent(locationId)}&productId=${encodeURIComponent(productId)}`);
  const payload = res.body || res;
  state.spaceLastResult = payload;
  document.getElementById('space-doc-output').textContent = JSON.stringify(payload, null, 2);
  renderSpaceDocSummary(payload, locationId, productId);
  syncJsonTree('space-doc-output');
  pushRecent('locations', String(locationId));
  pushRecent('products', { productId: String(productId) });
  savePrefs({ spaceDocLocation: String(locationId), spaceDocProduct: String(productId) });
}
